  and issue_type_name = #{issueTypeName}

select count(*)
from issue_status
where issue_status_id = #{initialStatusId}
  and user_id = #{userId}

select count(distinct project_id)
from project
where owner_id = #{userId}


        and project_id in

            #{projectId}



