mapper.delete:
delete from issue_type_project
where issue_type_id in (
    select issue_type_id
    from issue_type
    where issue_type_id = #{issueTypeId}
      and user_id = #{userId}
)

delete from issue_type_field_setting
where issue_type_id in (
    select issue_type_id
    from issue_type
    where issue_type_id = #{issueTypeId}
      and user_id = #{userId}
)

delete from issue_type
where issue_type_id = #{issueTypeId}
